# Find alerts that fire often but rarely matter
# (auto-resolved within 5 minutes most of the time)
topk(10,
  sum by (alertname) (
    changes(ALERTS_FOR_STATE[7d])
  )
)

# Find alerts that page but the system recovers on its own
sum by (alertname) (
  ALERTS{alertstate="firing", severity="page"}
  unless on(alertname) ALERTS{alertstate="firing"} offset 5m
)

