#!/usr/bin/env python3
"""Generate alertmanager.yaml routes from services.yaml."""
import yaml

with open('services.yaml') as f:
    catalog = yaml.safe_load(f)

routes = []
receivers = []

for svc in catalog['services']:
    routes.append({
        'match': {'service': svc['name']},
        'receiver': f"{svc['team']}-oncall",
        'continue': False,
    })

for team in {s['team'] for s in catalog['services']}:
    receivers.append({
        'name': f'{team}-oncall',
        'pagerduty_configs': [{
            'service_key': f'$PD_KEY_{team.upper()}',
            'description': '{{ .GroupLabels.alertname }} - {{ .GroupLabels.service }}',
        }],
        'slack_configs': [{
            'channel': f'#{team}-alerts',
            'send_resolved': True,
        }],
    })

config = {
    'route': {
        'group_by': ['alertname', 'service'],
        'receiver': 'default',
        'routes': routes,
    },
    'receivers': receivers + [{'name': 'default', 'slack_configs': [{'channel': '#alerts-unrouted'}]}],
}

with open('alertmanager.generated.yaml', 'w') as f:
    yaml.dump(config, f)
